BEGIN;
CREATE TABLE IF NOT EXISTS `migrations` (`id` integer primary key auto_increment not null, `migration` varchar(255) not null, `batch` integer not null);
CREATE TABLE IF NOT EXISTS `users` (`id` integer primary key auto_increment not null, `name` varchar(255) not null, `email` varchar(255) not null, `email_verified_at` datetime, `password` varchar(255) not null, `role` varchar(255) not null default 'staff', `office_id` integer, `remember_token` varchar(255), `created_at` datetime, `updated_at` datetime, foreign key(`office_id`) references `offices`(`id`) on delete cascade);
CREATE TABLE IF NOT EXISTS `password_reset_tokens` (`email` varchar(255) not null, `token` varchar(255) not null, `created_at` datetime, primary key (`email`));
CREATE TABLE IF NOT EXISTS `sessions` (`id` varchar(255) not null, `user_id` integer, `ip_address` varchar(255), `user_agent` text, `payload` text not null, `last_activity` integer not null, primary key (`id`));
CREATE TABLE IF NOT EXISTS `cache` (`key` varchar(255) not null, `value` text not null, `expiration` integer not null, primary key (`key`));
CREATE TABLE IF NOT EXISTS `cache_locks` (`key` varchar(255) not null, `owner` varchar(255) not null, `expiration` integer not null, primary key (`key`));
CREATE TABLE IF NOT EXISTS `jobs` (`id` integer primary key auto_increment not null, `queue` varchar(255) not null, `payload` text not null, `attempts` integer not null, `reserved_at` integer, `available_at` integer not null, `created_at` integer not null);
CREATE TABLE IF NOT EXISTS `job_batches` (`id` varchar(255) not null, `name` varchar(255) not null, `total_jobs` integer not null, `pending_jobs` integer not null, `failed_jobs` integer not null, `failed_job_ids` text not null, `options` text, `cancelled_at` integer, `created_at` integer not null, `finished_at` integer, primary key (`id`));
CREATE TABLE IF NOT EXISTS `failed_jobs` (`id` integer primary key auto_increment not null, `uuid` varchar(255) not null, `connection` text not null, `queue` text not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS `queues` (`id` integer primary key auto_increment not null, `user_id` integer, `name` varchar(255) not null, `number` integer not null, `status` varchar(255) check (`status` in ('waiting', 'serving', 'done', 'skipped')) not null default 'waiting', `created_at` datetime, `updated_at` datetime);
CREATE TABLE IF NOT EXISTS `visitors` (`id` integer primary key auto_increment not null, `name` varchar(255) not null, `contact_number` varchar(255) not null, `id_number` varchar(255), `office_id` integer not null, `previous_office_id` integer, `queue_number` integer not null, `ticket_number` integer not null, `type` varchar(255) check (`type` in ('student', 'visitor')), `cashier_id` integer, `priority` tinyint(1) not null default '0', `status` varchar(255) check (`status` in ('waiting', 'serving', 'done', 'skipped', 'transferred')) not null default 'waiting', `created_at` datetime, `updated_at` datetime, foreign key(`office_id`) references `offices`(`id`) on delete cascade, foreign key(`previous_office_id`) references `offices`(`id`) on delete set null, foreign key(`cashier_id`) references `users`(`id`) on delete set null);
CREATE TABLE IF NOT EXISTS `offices` (`id` integer primary key auto_increment not null, `name` varchar(255) not null, `abbreviation` varchar(255) not null, `priority_counter` integer not null default '0', `created_at` datetime, `updated_at` datetime);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX `users_email_unique` on `users` (`email`);
CREATE INDEX `sessions_user_id_index` on `sessions` (`user_id`);
CREATE INDEX `sessions_last_activity_index` on `sessions` (`last_activity`);
CREATE INDEX `jobs_queue_index` on `jobs` (`queue`);
CREATE UNIQUE INDEX `failed_jobs_uuid_unique` on `failed_jobs` (`uuid`);
CREATE UNIQUE INDEX `queues_number_unique` on `queues` (`number`);
CREATE UNIQUE INDEX `offices_name_unique` on `offices` (`name`);
CREATE UNIQUE INDEX `offices_abbreviation_unique` on `offices` (`abbreviation`);
COMMIT;
